<script setup lang="ts">
const supabase = useSupabaseClient<any>()
const state = ref<any>(null), loading = ref(true), message = ref(''), busy = ref('')
const privacy = reactive({ enabled: true, share_aggregate: true, retention_days: 30, minimum_cohort: 5, noise_level: .1 })
const accessibility = reactive({ density: 'comfortable', explanation_depth: 'balanced', motion: 'system', contrast: 'system', text_scale: 1, keyboard_first: false })
const trust = reactive({ subject_slug: '', capabilities: 'portfolio:read,simulation:run', days: 90 })
async function authed<T>(url: string, options: any = {}) { const { data: { session } } = await supabase.auth.getSession(); return $fetch<T>(url, { ...options, headers: { ...(options.headers || {}), ...(session?.access_token ? { authorization: `Bearer ${session.access_token}` } : {}) } }) }
async function load() { loading.value = true; try { state.value = await authed('/api/adaptive/evolution'); Object.assign(privacy, state.value.privacy || {}); Object.assign(accessibility, state.value.accessibility || {}) } finally { loading.value = false } }
async function act(action: string, values: any = {}) { busy.value = action; message.value = ''; try { const result: any = await authed('/api/adaptive/evolution', { method: 'POST', body: { action, values, objective: values.objective } }); message.value = action === 'simulate_interface' ? `Twin complete: ${Math.round(result.simulation.projected_outcome.expected_completion_lift * 100)}% projected completion lift with zero navigation drift.` : 'Capability fabric updated.'; await load(); if (action === 'update_accessibility') window.dispatchEvent(new CustomEvent('orchestrator:accessibility', { detail: result.accessibility })) } catch (e: any) { message.value = e?.data?.message || e?.message || 'Update failed.' } finally { busy.value = '' } }
async function inspectLifecycle() { busy.value = 'lifecycle'; try { const result: any = await authed('/api/connectors/lifecycle', { method: 'POST' }); message.value = `${result.accounts.length} credential${result.accounts.length === 1 ? '' : 's'} inspected; due OAuth tokens refresh automatically.`; await load() } catch (e: any) { message.value = e?.data?.message || e?.message || 'Lifecycle inspection failed.' } finally { busy.value = '' } }
function issueTrust() { return act('issue_federated_credential', { ...trust, capabilities: trust.capabilities.split(',').map(item => item.trim()).filter(Boolean) }) }
onMounted(load)
</script>
<template><section id="capability-evolution" class="mt-5 rounded-xl border bg-white p-4" aria-labelledby="evolution-heading"><div class="flex flex-wrap items-start justify-between gap-3"><div><div class="text-[10px] font-semibold uppercase tracking-[.14em] text-indigo-600">Capability evolution fabric</div><h2 id="evolution-heading" class="mt-1 text-sm font-semibold">Trust, learn, adapt, and settle outcomes</h2><p class="mt-1 max-w-3xl text-xs text-gray-500">One governed layer extends the organizational passport without moving any canonical destination.</p></div><span v-if="state" class="rounded-full bg-indigo-50 px-2 py-1 text-[10px] text-indigo-700">navigation contract v{{ state.navigation_contract.version }} · {{ state.navigation_contract.invariant_routes.length }} invariant routes</span></div><div v-if="loading" class="mt-4 text-xs text-gray-400">Loading capability fabric…</div><template v-else-if="state"><div class="mt-4 grid gap-3 lg:grid-cols-2"><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Causal interface twin</h3><p class="mt-1 text-[10px] text-gray-500">Predict workflow improvements while enforcing zero layout or route drift.</p><button class="mt-3 rounded-lg bg-indigo-600 px-3 py-2 text-xs text-white" :disabled="!!busy" @click="act('simulate_interface',{ objective: 'highest-value-next-action' })">{{ busy === 'simulate_interface' ? 'Simulating…' : 'Simulate adaptive interface' }}</button><div v-if="state.simulations?.[0]" class="mt-3 rounded-lg bg-indigo-50 p-2 text-[10px] text-indigo-700">Latest: {{ Math.round(state.simulations[0].projected_outcome.expected_completion_lift * 100) }}% completion lift · {{ Math.round(state.simulations[0].projected_outcome.confidence * 100) }}% confidence · zero route changes</div></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Credential lifecycle broker</h3><p class="mt-1 text-[10px] text-gray-500">Monitor expiry and automatically refresh eligible OAuth tokens five minutes before use.</p><button class="mt-3 rounded-lg bg-gray-900 px-3 py-2 text-xs text-white" :disabled="!!busy" @click="inspectLifecycle">{{ busy === 'lifecycle' ? 'Inspecting…' : 'Inspect and refresh now' }}</button><div class="mt-3 text-[10px] text-gray-500">{{ state.lifecycle.length }} lifecycle event{{ state.lifecycle.length === 1 ? '' : 's' }} recorded</div></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Organizational skill graph</h3><p class="mt-1 text-[10px] text-gray-500">Demonstrated competency becomes portable evidence and can influence governed routing.</p><div class="mt-2 space-y-2"><div v-for="skill in state.skills" :key="skill.id" class="flex items-center justify-between rounded-lg bg-gray-50 p-2"><div><div class="text-xs font-medium">{{ skill.label }}</div><div class="text-[9px] text-gray-400">{{ skill.capability_grants.join(' · ') }}</div></div><button class="text-[10px] text-blue-600" @click="act('record_skill',{ skill_id: skill.id, level: 1, evidence: { source: 'user_demonstration' } })">Record evidence</button></div></div></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Federated passport trust</h3><p class="mt-1 text-[10px] text-gray-500">Issue scoped, expiring organization credentials signed by the Orchestrator trust root.</p><form class="mt-2 grid grid-cols-2 gap-2" @submit.prevent="issueTrust"><input v-model="trust.subject_slug" required placeholder="Partner organization slug" class="col-span-2 rounded-lg border px-3 py-2 text-xs"><input v-model="trust.capabilities" class="col-span-2 rounded-lg border px-3 py-2 text-xs"><input v-model.number="trust.days" type="number" min="1" max="365" class="rounded-lg border px-3 py-2 text-xs"><button class="rounded-lg bg-gray-900 px-3 py-2 text-xs text-white">Issue trust credential</button></form><div class="mt-2 text-[10px] text-gray-500">{{ state.trusted_credentials.length }} active credential{{ state.trusted_credentials.length === 1 ? '' : 's' }} inherited</div></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Privacy-preserving learning</h3><div class="mt-2 grid grid-cols-2 gap-2 text-[10px]"><label><input v-model="privacy.enabled" type="checkbox"> Learn my preferences</label><label><input v-model="privacy.share_aggregate" type="checkbox"> Share cohort aggregate</label><label>Retention days<input v-model.number="privacy.retention_days" type="number" min="1" max="365" class="mt-1 w-full rounded border px-2 py-1"></label><label>Minimum cohort<input v-model.number="privacy.minimum_cohort" type="number" min="3" max="100" class="mt-1 w-full rounded border px-2 py-1"></label></div><p class="mt-2 text-[10px]" :class="state.cohort_learning.status === 'available' ? 'text-emerald-600' : 'text-amber-600'">Cohort signal: {{ state.cohort_learning.status }}<span v-if="state.cohort_learning.reason"> · {{ state.cohort_learning.reason }}</span></p><button class="mt-3 rounded-lg border px-3 py-2 text-xs" @click="act('update_privacy',privacy)">Save privacy controls</button></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Cognitive accessibility profile</h3><div class="mt-2 grid grid-cols-2 gap-2"><select v-model="accessibility.density" aria-label="Interface density" class="rounded border px-2 py-1 text-xs"><option>compact</option><option>comfortable</option><option>spacious</option></select><select v-model="accessibility.explanation_depth" aria-label="Explanation depth" class="rounded border px-2 py-1 text-xs"><option>concise</option><option>balanced</option><option>detailed</option></select><select v-model="accessibility.motion" aria-label="Motion preference" class="rounded border px-2 py-1 text-xs"><option>system</option><option>reduced</option><option>none</option></select><select v-model="accessibility.contrast" aria-label="Contrast preference" class="rounded border px-2 py-1 text-xs"><option>system</option><option>high</option></select><label class="col-span-2 text-[10px]">Text scale {{ accessibility.text_scale }}×<input v-model.number="accessibility.text_scale" type="range" min="0.9" max="1.5" step="0.1" class="w-full"></label><label class="col-span-2 text-[10px]"><input v-model="accessibility.keyboard_first" type="checkbox"> Keyboard-first guidance</label></div><button class="mt-3 rounded-lg border px-3 py-2 text-xs" @click="act('update_accessibility',accessibility)">Apply accessibility profile</button></article></div><article class="mt-3 rounded-xl border p-4"><div class="flex items-center justify-between"><div><h3 class="text-xs font-semibold">Outcome-settled provider market</h3><p class="mt-1 text-[10px] text-gray-500">Routing learns from realized reliability, quality, latency, cost, and policy incidents.</p></div><span class="text-[10px] text-gray-400">{{ Object.keys(state.provider_performance).length }} providers with evidence</span></div><div class="mt-2 grid gap-2 md:grid-cols-3"><div v-for="(value,provider) in state.provider_performance" :key="provider" class="rounded-lg bg-gray-50 p-2 text-[10px]"><b>{{ provider }}</b> · {{ Math.round(value.reliability * 100) }}% reliable · {{ Math.round(value.average_quality * 100) }}% quality · {{ value.runs }} runs</div></div></article></template><p v-if="message" role="status" class="mt-3 rounded-lg bg-gray-50 p-2 text-xs text-gray-600">{{ message }}</p></section></template>
